// ===== GENERATE REPORT (Tamil / English) + COLLECT STUDENT DATA =====
var _lastSentSig='';
function genReport(lang){
window._reportLang=lang;
// Validate mandatory student details
var name=document.getElementById('sf-name').value.trim();
var email=document.getElementById('sf-email').value.trim();
var phone=document.getElementById('sf-phone').value.trim();
var location=document.getElementById('sf-location').value.trim();
var school=document.getElementById('sf-school').value.trim();
if(!name||!email||!phone||!location||!school){
alert('Please fill all mandatory fields in the Student Registration form above.');
document.getElementById('sf-name').scrollIntoView({behavior:'smooth',block:'center'});
document.getElementById('sf-name').focus();
return;
}
if(!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)){alert('Please enter a valid email address.');document.getElementById('sf-email').focus();return;}
if(phone.replace(/[^0-9]/g,'').length<10){alert('Please enter a valid mobile number.');document.getElementById('sf-phone').focus();return;}
var score=parseFloat(document.getElementById('p-score').textContent)||0;
if(score<=0){alert('Please enter your marks first to generate predictions.');return;}
// Send student data to Google Sheets (skip duplicate row if same student clicks both languages)
var sig=[name,email,phone,location,school,score].join('|');
if(sig!==_lastSentSig){
sendToGoogleSheets({name:name,email:email,phone:phone,location:location,school:school,score:score,category:document.getElementById('p-cat').value,hsc:document.getElementById('sf-hsc').value,language:(lang==='ta'?'Tamil':'English')});
_lastSentSig=sig;
}
// Generate the report in the chosen language
downloadPDFReport();
}

function sendToGoogleSheets(data){
// Deployed Apps Script Web App endpoint (live) — TNEA Portal sheet
const SHEET_URL='https://script.google.com/macros/s/AKfycbzuo9xI85LyE5znOgly6sx-yxYMwmUMHiX01_DftpB3TZ6VcNMMdKWjWAFno_O7Nk_o/exec';
const payload={
name:data.name,email:data.email,phone:data.phone,
location:data.location,school:data.school,
score:data.score,category:data.category,
hsc:data.hsc||'',language:data.language||'',
timestamp:new Date().toISOString(),
safeCount:document.getElementById('cnt-safe')?.textContent||'0',
closeCount:document.getElementById('cnt-close')?.textContent||'0',
totalCount:document.getElementById('cnt-total')?.textContent||'0'
};
fetch(SHEET_URL,{method:'POST',mode:'no-cors',headers:{'Content-Type':'text/plain;charset=utf-8'},body:JSON.stringify(payload)}).then(()=>{
console.log('Student data sent to Google Sheets successfully');
}).catch(err=>{
console.log('Google Sheets send attempted (no-cors mode):',err);
});
}

// ===== CONTACT FORM =====
function submitContactForm(){
var name=document.getElementById('reg-name').value.trim();
var phone=document.getElementById('reg-phone').value.trim();
var email=(document.getElementById('reg-email')||{}).value||'';
var interest=(document.getElementById('reg-interest')||{}).value||'';
if(!name||!phone){alert('Please enter your name and phone number.');return}
sendToGoogleSheets({name:name,email:email,phone:phone,location:'Contact Form',school:interest||'General',score:'N/A',category:'consultation',hsc:'',
safeCount:'0',closeCount:'0',totalCount:'Contact Request'});
document.getElementById('reg-name').value='';
document.getElementById('reg-phone').value='';
if(document.getElementById('reg-email'))document.getElementById('reg-email').value='';
if(document.getElementById('reg-interest'))document.getElementById('reg-interest').value='';
alert('Thank you, '+name+'! Our expert will call you within 24 hours. You can also reach us on WhatsApp.');
}

